// mm/src/steps/uploadStep.js
import React, { useMemo, useRef, useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { useWorkflow } from '../store/workflowContext';
import {
  saveWorkflowFile,
  deleteWorkflowFile,
  loadWorkflowFiles,
} from '../utils/fileStore';

const TAG_OPTIONS = [
  'Main Manuscript',
  'Book Cover',
  'Chapter',
  'Appendix',
  'Bibliography',
  'Index',
  'Preface',
  'Introduction',
  'Acknowledgments',
  'Other',
];

const CATEGORY_OPTIONS = [
  'Fiction',
  'Non-Fiction',
  'Business',
  'Self-Help',
  'Romance',
  'Fantasy',
  'Science Fiction',
  'Mystery/Thriller',
  'Biography',
  'History',
  'Other',
];

const SUBCATEGORY_BY_CATEGORY = {
  Fiction: ['Science Fiction', 'Fantasy', 'Romance', 'Mystery/Thriller', 'Literary', 'Historical', 'Other'],
  'Non-Fiction': ['Business', 'Self-Help', 'Biography', 'History', 'Health', 'Other'],
  Business: ['Entrepreneurship', 'Leadership', 'Marketing', 'Finance', 'Other'],
  'Self-Help': ['Mindset', 'Productivity', 'Relationships', 'Other'],
  Romance: ['Contemporary', 'Historical', 'Romantic Suspense', 'Other'],
  Fantasy: ['Epic', 'Urban', 'YA', 'Other'],
  'Science Fiction': ['Space Opera', 'Dystopian', 'Cyberpunk', 'YA', 'Other'],
  'Mystery/Thriller': ['Crime', 'Suspense', 'Detective', 'Other'],
  Biography: ['Memoir', 'Autobiography', 'Other'],
  History: ['Military', 'Ancient', 'Modern', 'Other'],
  Other: ['Other'],
};

const UploadStep = () => {
  const fileRef = useRef(null);

  const {
    manuscriptFiles = [],
    setManuscriptFiles,
    addFile,
    removeFile,
    setUploadPhase,
    uploadPhase = 'select',
    bookDetails,
    setBookDetails,
  } = useWorkflow();

  const [progress, setProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [localError, setLocalError] = useState('');

  const hasFiles = manuscriptFiles.length > 0;

  // --- On mount: hydrate context from IndexedDB if context is empty ---
  useEffect(() => {
    let cancelled = false;

    const hydrate = async () => {
      try {
        if (manuscriptFiles && manuscriptFiles.length > 0) return;

        const stored = await loadWorkflowFiles(); // [{id,file,name,size,tag,...}]
        if (cancelled) return;

        if (Array.isArray(stored) && stored.length > 0) {
          const mapped = stored.map((x) => ({
            id: x.id,
            name: x.name || x.file?.name || 'document',
            size: x.size ?? x.file?.size ?? 0,
            status: 'local',
            progress: 100,
            file: x.file,
            tag: x.tag || 'Main Manuscript',
            savedAt: x.savedAt,
          }));

          if (typeof setManuscriptFiles === 'function') {
            setManuscriptFiles(mapped);
          } else {
            // Fallback if setManuscriptFiles isn't exposed for some reason
            mapped.forEach((m) => addFile(m));
          }

          // If user already uploaded something earlier, put them on READY
          if (uploadPhase === 'select') setUploadPhase('ready');
        }
      } catch (e) {
        console.error('Failed to hydrate files from IndexedDB:', e);
      }
    };

    hydrate();
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const category = bookDetails?.category || '';
  const subOptions = useMemo(() => {
    const key = category && SUBCATEGORY_BY_CATEGORY[category] ? category : 'Other';
    return SUBCATEGORY_BY_CATEGORY[key] || ['Other'];
  }, [category]);

  const upsertFile = (fileObj) => {
    addFile(fileObj);
  };

  // ✅ NEW: Store files locally (IndexedDB), do NOT call backend here
  const handleFiles = async (files) => {
    setLocalError('');
    if (!files || files.length === 0) return;

    // Current behavior: accept first file only
    const file = files[0];

    const id = uuidv4();
    const baseMeta = {
      id,
      name: file.name,
      size: file.size,
      status: 'local',
      progress: 100,
      file, // keep File object for preview extraction
      tag: 'Main Manuscript',
    };

    // UI feedback (no real upload, but keep your progress UX)
    setIsUploading(true);
    setProgress(0);

    try {
      // Save to context
      upsertFile(baseMeta);

      // Save to IndexedDB so it survives navigation to register/login
      await saveWorkflowFile({
        id,
        file,
        name: file.name,
        size: file.size,
        tag: baseMeta.tag,
      });

      setProgress(100);
      setUploadPhase('ready');
    } catch (err) {
      console.error('Local save failed', err);
      setLocalError('Could not store your file locally. Please try again.');
      upsertFile({ ...baseMeta, status: 'error', progress: 0 });
      setProgress(0);
    } finally {
      setIsUploading(false);
    }
  };

  const onDrop = (e) => {
    e.preventDefault();
    handleFiles(e.dataTransfer.files);
  };

  const onChoose = (e) => {
    handleFiles(e.target.files);
  };

  const onStartAnalysis = () => {
    setUploadPhase('metadata');
  };

  // ✅ NEW: persist tag changes to IndexedDB too
  const onTagChange = async (id, newTag) => {
    const f = manuscriptFiles.find((x) => x.id === id);
    if (!f) return;

    upsertFile({ id, tag: newTag });

    try {
      // Update stored record with same id
      await saveWorkflowFile({
        id,
        file: f.file,
        name: f.name,
        size: f.size,
        tag: newTag,
      });
    } catch (e) {
      console.error('Failed to update tag in IndexedDB:', e);
    }
  };

  // ✅ NEW: remove from context + IndexedDB
  const onDelete = async (id) => {
    try {
      if (typeof removeFile === 'function') removeFile(id);
      await deleteWorkflowFile(id);
    } catch (e) {
      console.error('Failed to delete from IndexedDB:', e);
    }
  };

  const renderFileRow = (f, showTagDropdown) => (
    <li
      key={f.id}
      className="flex items-center justify-between border border-slate-200 bg-white rounded-lg px-4 py-3"
    >
      <div className="flex items-center gap-3 min-w-0">
        <div className="w-9 h-9 rounded-lg bg-slate-100 flex items-center justify-center text-slate-500">
          📄
        </div>
        <div className="min-w-0">
          <div className="font-medium text-slate-900 truncate">{f.name}</div>
          <div className="text-xs text-slate-500">
            {(f.size ? (f.size / (1024 * 1024)).toFixed(2) : '0.00')} MB • {f.status || 'ready'}
          </div>
        </div>
      </div>

      <div className="flex items-center gap-3">
        {showTagDropdown && (
          <select
            value={f.tag || 'Main Manuscript'}
            onChange={(e) => onTagChange(f.id, e.target.value)}
            className="border border-slate-200 rounded-md px-3 py-2 text-sm bg-white"
          >
            {TAG_OPTIONS.map((opt) => (
              <option key={opt} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        )}

        <button
          type="button"
          onClick={() => onDelete(f.id)}
          className="text-slate-400 hover:text-red-500 transition"
          aria-label="Remove file"
          title="Remove"
        >
          🗑️
        </button>
      </div>
    </li>
  );

  // PHASE 1: SELECT (upload dropzone)
  if (uploadPhase === 'select') {
    return (
      <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 flex flex-col items-center bg-white">
        <div className="mb-4 text-slate-700 text-center">
          <h3 className="text-2xl font-semibold">Upload Your Book Files</h3>
          <p className="text-sm text-slate-500">PDF, DOCX, TXT, MD — up to 50MB</p>
        </div>

        <div
          onDrop={onDrop}
          onDragOver={(e) => e.preventDefault()}
          className="w-full py-12 flex items-center justify-center rounded-lg bg-gradient-to-br from-slate-50 to-white border border-slate-100"
        >
          <div className="text-center">
            <input ref={fileRef} type="file" onChange={onChoose} className="hidden" />
            <button
              type="button"
              onClick={() => fileRef.current?.click()}
              className="px-6 py-3 bg-blue-600 text-white rounded-md shadow"
            >
              Upload a file
            </button>
            <div className="mt-4 text-sm text-slate-500">or drag and drop here</div>
          </div>
        </div>

        <div className="mt-6 w-full">
          {localError ? <div className="text-sm text-red-600">{localError}</div> : null}

          {isUploading && (
            <div className="w-full bg-slate-100 rounded overflow-hidden">
              <div style={{ width: `${progress}%` }} className="h-2 bg-blue-600 transition-all" />
              <div className="text-sm text-slate-600 mt-2">
                {progress < 100 ? `Saving locally: ${progress}%` : 'Saved locally ✅'}
              </div>
            </div>
          )}

          {hasFiles && (
            <div className="mt-4 w-full">
              <h4 className="text-sm font-medium text-slate-700">Files</h4>
              <ul className="mt-2 space-y-2">{manuscriptFiles.map((f) => renderFileRow(f, false))}</ul>
            </div>
          )}
        </div>
      </div>
    );
  }

  // PHASE 2: READY (Start AI Analysis screen)
  if (uploadPhase === 'ready') {
    return (
      <div className="border border-slate-200 rounded-xl p-8 bg-white">
        <div className="text-center mb-6">
          <h3 className="text-2xl font-semibold text-slate-900">Upload Your Manuscript</h3>
          <p className="text-sm text-slate-500 mt-1">
            Upload your book files for AI analysis and professional formatting.
          </p>
        </div>

        <div className="max-w-3xl mx-auto">
          <div className="border border-slate-200 rounded-xl p-4 bg-gradient-to-br from-slate-50 to-white">
            {localError ? <div className="text-sm text-red-600 mb-3">{localError}</div> : null}

            <ul className="space-y-3">{manuscriptFiles.map((f) => renderFileRow(f, false))}</ul>

            <div className="mt-5 flex items-center justify-center gap-3">
              <button
                type="button"
                onClick={() => fileRef.current?.click()}
                className="px-4 py-2 rounded-md border border-slate-200 bg-white text-slate-700 hover:bg-slate-50"
              >
                Add Another File
              </button>

              <button
                type="button"
                onClick={onStartAnalysis}
                className="px-6 py-3 bg-blue-600 text-white rounded-md shadow hover:bg-blue-700"
              >
                Start AI Analysis →
              </button>

              <input ref={fileRef} type="file" onChange={onChoose} className="hidden" />
            </div>

            {isUploading ? (
              <div className="mt-4 w-full bg-slate-100 rounded overflow-hidden">
                <div style={{ width: `${progress}%` }} className="h-2 bg-blue-600 transition-all" />
                <div className="text-sm text-slate-600 mt-2">
                  {progress < 100 ? `Saving locally: ${progress}%` : 'Saved locally ✅'}
                </div>
              </div>
            ) : null}
          </div>
        </div>
      </div>
    );
  }

  // PHASE 3: METADATA (Basic Info + Organize Files)
  return (
    <div className="space-y-8">
      {/* Basic Information */}
      <div className="border border-slate-200 rounded-xl p-8 bg-white">
        <h3 className="text-2xl font-semibold text-slate-900">Basic Information</h3>

        <div className="mt-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Book Title *</label>
            <input
              value={bookDetails?.title || ''}
              onChange={(e) => setBookDetails?.({ ...(bookDetails || {}), title: e.target.value })}
              placeholder="Enter your book title"
              className="w-full border border-slate-200 rounded-md px-4 py-3 outline-none focus:ring-2 focus:ring-blue-200"
            />
          </div>

          {/* Book Author */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Book Author *</label>
            <input
              value={bookDetails?.author || ''}
              onChange={(e) =>
                setBookDetails?.({
                  ...(bookDetails || {}),
                  author: e.target.value,
                })
              }
              placeholder="Enter the author name"
              className="w-full border border-slate-200 rounded-md px-4 py-3 outline-none focus:ring-2 focus:ring-blue-200"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">Category *</label>
              <select
                value={bookDetails?.category || ''}
                onChange={(e) =>
                  setBookDetails?.({
                    ...(bookDetails || {}),
                    category: e.target.value,
                    subcategory: '',
                  })
                }
                className="w-full border border-slate-200 rounded-md px-4 py-3 bg-white outline-none focus:ring-2 focus:ring-blue-200"
              >
                <option value="">Select category</option>
                {CATEGORY_OPTIONS.map((opt) => (
                  <option key={opt} value={opt}>
                    {opt}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">Subcategory *</label>
              <select
                value={bookDetails?.subcategory || ''}
                onChange={(e) =>
                  setBookDetails?.({
                    ...(bookDetails || {}),
                    subcategory: e.target.value,
                  })
                }
                className="w-full border border-slate-200 rounded-md px-4 py-3 bg-white outline-none focus:ring-2 focus:ring-blue-200"
              >
                <option value="">Select subcategory</option>
                {subOptions.map((opt) => (
                  <option key={opt} value={opt}>
                    {opt}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </div>

      {/* Organize Files */}
      <div className="border border-slate-200 rounded-xl p-8 bg-white">
        <h3 className="text-2xl font-semibold text-slate-900">Organize Your Files</h3>
        <p className="text-sm text-slate-500 mt-2">
          Tag your files to help organize them properly. Files tagged as "Book Cover" will remain separate.
        </p>

        <div className="mt-6 border border-slate-200 rounded-xl p-4 bg-white">
          {localError ? <div className="text-sm text-red-600 mb-3">{localError}</div> : null}

          <ul className="space-y-3">{manuscriptFiles.map((f) => renderFileRow(f, true))}</ul>

          <div className="mt-5">
            <input ref={fileRef} type="file" onChange={onChoose} className="hidden" />
            <button
              type="button"
              onClick={() => fileRef.current?.click()}
              className="px-4 py-2 rounded-md border border-slate-200 bg-white text-slate-700 hover:bg-slate-50"
            >
              + Add Another File
            </button>
          </div>

          {isUploading ? (
            <div className="mt-4 w-full bg-slate-100 rounded overflow-hidden">
              <div style={{ width: `${progress}%` }} className="h-2 bg-blue-600 transition-all" />
              <div className="text-sm text-slate-600 mt-2">
                {progress < 100 ? `Saving locally: ${progress}%` : 'Saved locally ✅'}
              </div>
            </div>
          ) : null}
        </div>
      </div>
    </div>
  );
};

export default UploadStep;
